/**
 * Notification log model — types for tracking notification delivery history.
 *
 * Each log entry captures what was sent, to whom, via which channel,
 * and whether delivery succeeded or failed.
 */

import type {
  NotificationChannel,
  NotificationType,
  NotificationPriority,
} from './notification.js';

/**
 * Delivery status of a logged notification.
 */
export type DeliveryStatus = 'delivered' | 'failed';

/**
 * A log entry recording a single notification delivery attempt.
 */
export interface NotificationLogEntry {
  /** Unique log entry ID. */
  id: string;
  /** The notification ID this log entry refers to. */
  notificationId: string;
  /** Recipient identifier (email, user ID, etc.). */
  recipient: string;
  /** Channel used for delivery. */
  channel: NotificationChannel;
  /** Notification category. */
  type: NotificationType;
  /** Delivery priority. */
  priority: NotificationPriority;
  /** Notification subject/title. */
  subject: string;
  /** Whether delivery succeeded or failed. */
  status: DeliveryStatus;
  /** Error message if delivery failed. */
  error?: string;
  /** When the notification was sent/attempted. */
  timestamp: Date;
}

/**
 * Query filters for searching notification history.
 */
export interface NotificationHistoryQuery {
  /** Filter by recipient. */
  recipient?: string;
  /** Filter by notification type. */
  type?: NotificationType;
  /** Filter by delivery channel. */
  channel?: NotificationChannel;
  /** Filter by delivery status. */
  status?: DeliveryStatus;
  /** Filter entries on or after this date. */
  startDate?: Date;
  /** Filter entries on or before this date. */
  endDate?: Date;
}

/**
 * Notification history service — logs and queries sent notification records.
 *
 * Injected into NotificationService via setHistoryService() to track
 * all delivery attempts. Provides queryable history by recipient, type,
 * channel, status, and date range.
 */

import type { NotificationRecord } from '../models/notification.js';
import type {
  NotificationLogEntry,
  NotificationHistoryQuery,
} from '../models/notification-log.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset the log ID counter (for testing). */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private entries: NotificationLogEntry[] = [];

  /**
   * Log a notification record. Called by NotificationService after each
   * delivery attempt.
   */
  log(record: NotificationRecord): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: record.id,
      recipient: record.recipient,
      channel: record.deliveredVia,
      type: record.type,
      priority: record.priority,
      subject: record.subject,
      status: record.success ? 'delivered' : 'failed',
      error: record.error,
      timestamp: record.deliveredAt,
    };
    this.entries.push(entry);
    return entry;
  }

  /**
   * Query notification history with optional filters.
   * All filters are ANDed together.
   */
  query(filters: NotificationHistoryQuery = {}): NotificationLogEntry[] {
    return this.entries.filter((entry) => {
      if (filters.recipient !== undefined && entry.recipient !== filters.recipient) {
        return false;
      }
      if (filters.type !== undefined && entry.type !== filters.type) {
        return false;
      }
      if (filters.channel !== undefined && entry.channel !== filters.channel) {
        return false;
      }
      if (filters.status !== undefined && entry.status !== filters.status) {
        return false;
      }
      if (filters.startDate !== undefined && entry.timestamp < filters.startDate) {
        return false;
      }
      if (filters.endDate !== undefined && entry.timestamp > filters.endDate) {
        return false;
      }
      return true;
    });
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.query({ recipient });
  }

  /**
   * Get all log entries of a specific notification type.
   */
  getByType(type: NotificationHistoryQuery['type']): NotificationLogEntry[] {
    return this.query({ type });
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.query({ startDate, endDate });
  }

  /**
   * Get the total number of log entries.
   */
  getCount(): number {
    return this.entries.length;
  }

  /**
   * Get all log entries.
   */
  getAll(): NotificationLogEntry[] {
    return [...this.entries];
  }

  /**
   * Clear all log entries (useful for testing).
   */
  clear(): void {
    this.entries = [];
  }
}

