import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationRecord } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    historyService = new NotificationHistoryService();
    resetLogIdCounter();
  });

  function makeRecord(overrides: Partial<NotificationRecord> = {}): NotificationRecord {
    return {
      id: 'notif-0001',
      type: 'order-confirmation',
      channels: ['email'],
      priority: 'high',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      deliveredVia: 'email',
      success: true,
      deliveredAt: new Date('2026-03-15T10:00:00Z'),
      createdAt: new Date('2026-03-15T10:00:00Z'),
      ...overrides,
    };
  }

  describe('log', () => {
    it('should create a log entry from a notification record', () => {
      const record = makeRecord();
      const entry = historyService.log(record);

      expect(entry.id).toBe('log-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order-confirmation');
      expect(entry.priority).toBe('high');
      expect(entry.subject).toBe('Order Confirmation: order-1');
      expect(entry.status).toBe('delivered');
      expect(entry.error).toBeUndefined();
      expect(entry.timestamp).toEqual(new Date('2026-03-15T10:00:00Z'));
    });

    it('should log failed deliveries with error message', () => {
      const record = makeRecord({
        success: false,
        error: 'Connection timeout',
      });
      const entry = historyService.log(record);

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Connection timeout');
    });

    it('should generate sequential log IDs', () => {
      historyService.log(makeRecord({ id: 'notif-0001' }));
      historyService.log(makeRecord({ id: 'notif-0002' }));

      const entries = historyService.getAll();
      expect(entries[0]?.id).toBe('log-0001');
      expect(entries[1]?.id).toBe('log-0002');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.log(makeRecord({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        type: 'order-confirmation',
        deliveredVia: 'email',
        success: true,
        deliveredAt: new Date('2026-03-10T10:00:00Z'),
      }));
      historyService.log(makeRecord({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        type: 'order-status-update',
        deliveredVia: 'email',
        success: false,
        error: 'Delivery failed',
        deliveredAt: new Date('2026-03-15T10:00:00Z'),
      }));
      historyService.log(makeRecord({
        id: 'notif-0003',
        recipient: 'alice@example.com',
        type: 'welcome',
        deliveredVia: 'webhook',
        channels: ['webhook'],
        success: true,
        deliveredAt: new Date('2026-03-20T10:00:00Z'),
      }));
    });

    it('should return all entries when no filters are provided', () => {
      const results = historyService.query();
      expect(results).toHaveLength(3);
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by notification type', () => {
      const results = historyService.query({ type: 'order-confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order-confirmation');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by delivery status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-03-12T00:00:00Z'),
        endDate: new Date('2026-03-18T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by startDate only', () => {
      const results = historyService.query({
        startDate: new Date('2026-03-15T00:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should filter by endDate only', () => {
      const results = historyService.query({
        endDate: new Date('2026-03-15T10:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters (AND logic)', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'email',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order-confirmation');
    });

    it('should return empty array when no entries match', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      historyService.log(makeRecord({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        type: 'order-confirmation',
        deliveredAt: new Date('2026-03-10T10:00:00Z'),
      }));
      historyService.log(makeRecord({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        type: 'order-status-update',
        deliveredAt: new Date('2026-03-15T10:00:00Z'),
      }));
    });

    it('should get entries by recipient', () => {
      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });

    it('should get entries by type', () => {
      const results = historyService.getByType('order-status-update');
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order-status-update');
    });

    it('should get entries by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-03-09T00:00:00Z'),
        new Date('2026-03-11T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });
  });

  describe('management', () => {
    it('should count entries', () => {
      expect(historyService.getCount()).toBe(0);
      historyService.log(makeRecord());
      expect(historyService.getCount()).toBe(1);
    });

    it('should return all entries', () => {
      historyService.log(makeRecord({ id: 'notif-0001' }));
      historyService.log(makeRecord({ id: 'notif-0002' }));
      expect(historyService.getAll()).toHaveLength(2);
    });

    it('should clear entries', () => {
      historyService.log(makeRecord());
      historyService.clear();
      expect(historyService.getCount()).toBe(0);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailNotificationAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailNotificationAdapter({
        recipientResolver: async (recipient) => {
          const users: Record<string, string> = {
            'user-1': 'alice@example.com',
          };
          return users[recipient] ?? null;
        },
      });
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications sent via EventBus', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getCount()).toBe(1);
      const entries = historyService.getAll();
      expect(entries[0]?.notificationId).toBe('notif-0001');
      expect(entries[0]?.recipient).toBe('alice@example.com');
      expect(entries[0]?.type).toBe('order-confirmation');
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.status).toBe('delivered');
    });

    it('should log failed deliveries when no adapter is registered', async () => {
      const noAdapterService = new NotificationService(eventBus);
      noAdapterService.setHistoryService(historyService);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const entries = historyService.getAll();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.status).toBe('failed');
      expect(entries[0]?.error).toContain('No adapter');
    });

    it('should log multiple notifications from different events', async () => {
      const createEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(createEvent);
      await eventBus.emit(statusEvent);

      expect(historyService.getCount()).toBe(2);

      const confirmations = historyService.getByType('order-confirmation');
      expect(confirmations).toHaveLength(1);

      const statusUpdates = historyService.getByType('order-status-update');
      expect(statusUpdates).toHaveLength(1);
    });

    it('should be queryable by recipient after integration', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('bob@example.com')).toHaveLength(0);
    });
  });
});

